// Monta o corpo HTML do digest a partir das proposicoes retornadas pelo Postgres.
const itens = $input.all().map(i => i.json);
const total = itens.length;
const hoje = new Date().toLocaleDateString('pt-BR');

let linhas = itens.map(p => {
  const titulo = `${p.sigla_tipo || ''} ${p.numero || ''}/${p.ano || ''}`.trim();
  return `
    <tr>
      <td style="padding:8px;border-bottom:1px solid #eee;font-weight:600;">${titulo}</td>
      <td style="padding:8px;border-bottom:1px solid #eee;"><span style="background:#e8f0fe;color:#1a3e72;padding:2px 8px;border-radius:10px;font-size:12px;">${p.tema}</span> <small style="color:#888;">(${p.tema_score})</small></td>
      <td style="padding:8px;border-bottom:1px solid #eee;color:#333;">${(p.resumo || '').replace(/</g,'&lt;')}</td>
    </tr>`;
}).join('');

if (total === 0) {
  linhas = `<tr><td colspan="3" style="padding:12px;color:#888;">Nenhuma proposicao nova nas ultimas 24h.</td></tr>`;
}

const html = `
  <div style="font-family:Arial,Helvetica,sans-serif;max-width:680px;margin:auto;">
    <h2 style="color:#1a3e72;">Bussola Publica — Radar Legislativo (${hoje})</h2>
    <p style="color:#444;">Pipeline executado com sucesso as 06h. <b>${total}</b> proposicao(oes) priorizada(s) nas ultimas 24h, classificadas por tema (IA) e com resumo executivo (IA).</p>
    <table style="border-collapse:collapse;width:100%;font-size:14px;">
      <thead>
        <tr style="background:#1a3e72;color:#fff;text-align:left;">
          <th style="padding:8px;">Proposicao</th>
          <th style="padding:8px;">Tema (score)</th>
          <th style="padding:8px;">Resumo executivo</th>
        </tr>
      </thead>
      <tbody>${linhas}</tbody>
    </table>
    <p style="color:#999;font-size:12px;margin-top:16px;">Gerado automaticamente pelo pipeline Bussola Publica (n8n + Supabase + OpenAI).</p>
  </div>`;

return [{ json: { total, hoje, html, assunto: `Bussola Publica — ${total} proposicoes novas (${hoje})` } }];
